import type { ScenarioQuestion } from "./types";
type D = "beginner" | "intermediate" | "advanced";
function q(id: string, g: string, s: string, sc: string, qu: string, a: string, f: string, d: D): ScenarioQuestion {
  return { id, formatType: "scenario", categoryGroup: g, subcategory: s, scenarioPrompt: sc, question: qu, exampleAnswer: a, feedback: f, difficulty: d };
}
const ip = "interview_preparation", ws = "workplace_scenarios", ct = "clinical_transition", pd = "professional_development", cn = "career_navigation";

export const bulkGeneratedBatch14: ScenarioQuestion[] = [
  q("sq-bg14-1",ip,"clinical_judgment","A patient on TPN develops hepatic steatosis.","How does TPN cause liver complications?","Prolonged TPN causes hepatic steatosis from excess carbohydrate calories converted to fat, cholestasis from lack of enteral stimulation, and biliary sludge. Prevention includes: cycling TPN, initiating enteral feeds as soon as possible, using lipid-based calories, and monitoring liver function weekly. I would trend LFTs and advocate for enteral nutrition when feasible.","TPN hepatic complications prevention.","intermediate"),
  q("sq-bg14-2",ip,"clinical_judgment","A patient develops hepatopulmonary syndrome.","What is hepatopulmonary syndrome?","HPS occurs in cirrhosis when intrapulmonary vascular dilation causes right-to-left shunting, leading to hypoxemia that worsens when sitting upright (platypnea-orthodeoxia). This is the opposite of typical dyspnea patterns. The definitive treatment is liver transplantation. I would administer supplemental oxygen and position for optimal oxygenation.","HPS with paradoxical positional hypoxemia.","advanced"),
  q("sq-bg14-3",ip,"clinical_judgment","A patient develops phlegmasia cerulea dolens.","What is phlegmasia cerulea dolens?","Phlegmasia cerulea dolens is massive iliofemoral DVT causing complete venous obstruction with leg cyanosis, severe edema, and risk of venous gangrene and compartment syndrome. This is a vascular emergency requiring emergent thrombolysis, thrombectomy, or fasciotomy. I would elevate the leg, anticoagulate, and prepare for emergent vascular surgery.","Phlegmasia cerulea dolens surgical emergency.","advanced"),
  q("sq-bg14-4",ip,"clinical_judgment","A patient develops transfusion-associated circulatory overload.","How does TACO differ from TRALI?","TACO presents with hypertension, pulmonary edema, and elevated BNP from fluid overload—it responds to diuretics. TRALI presents with hypotension, bilateral infiltrates, and normal BNP from capillary leak—it does not respond to diuretics. Differentiation is critical because treatment is opposite. I would check BNP, fluid balance, and blood pressure to distinguish.","TACO versus TRALI differentiation.","advanced"),
  q("sq-bg14-5",ip,"clinical_judgment","A patient develops Leriche syndrome.","What is Leriche syndrome?","Leriche syndrome is chronic aortoiliac occlusive disease presenting with the classic triad: claudication of buttocks and thighs, erectile dysfunction, and absent femoral pulses bilaterally. Treatment includes surgical bypass or endovascular intervention. I would assess peripheral pulses, check ankle-brachial index, and facilitate vascular surgery consultation.","Leriche syndrome triad recognition.","advanced"),
  q("sq-bg14-6",ip,"clinical_judgment","A patient on amiodarone develops thyrotoxicosis.","How does amiodarone cause thyroid dysfunction?","Amiodarone contains 37% iodine by weight and can cause either hypothyroidism (Wolff-Chaikoff effect) or thyrotoxicosis. Type 1 is from iodine-induced excess hormone production; Type 2 is from destructive thyroiditis releasing stored hormone. I would check thyroid function, differentiate the type, and involve endocrinology. The treatment differs between types.","Amiodarone thyroid toxicity dual mechanism.","advanced"),
  q("sq-bg14-7",ip,"clinical_judgment","A patient develops Brugada syndrome on ECG.","What is Brugada syndrome?","Brugada syndrome shows a characteristic coved ST elevation in V1-V3 with risk of sudden cardiac death from ventricular fibrillation. It is often unmasked by fever, medications, or electrolyte disturbances. I would ensure continuous monitoring, avoid triggering medications (class IA antiarrhythmics, TCAs, lithium), treat fever aggressively, and refer for possible ICD placement.","Brugada syndrome recognition with trigger avoidance.","advanced"),
  q("sq-bg14-8",ip,"behavioral","You are asked about dealing with failure.","How do you handle professional setbacks?","I treat setbacks as data, not verdicts. When I failed my first IV insertion attempt during clinical, I analyzed what went wrong, practiced the technique, and succeeded the next time. Failure is not permanent unless I stop trying. I maintain perspective: one bad moment does not define my competence as a nurse.","Growth-oriented failure processing.","beginner"),
  q("sq-bg14-9",ip,"behavioral","You are asked about your biggest accomplishment.","What is your greatest professional achievement?","During my community health rotation, I identified a gap in diabetes education for a Spanish-speaking population. I collaborated with an interpreter and local health department to create culturally appropriate educational materials and hosted a community workshop that reached 45 individuals. Three months later, follow-up showed improved A1c levels in participants.","Community health impact achievement.","intermediate"),
  q("sq-bg14-10",ip,"scenario_responses","A patient is worried about addiction from pain medication.","How would you address opioid addiction fears?","I would provide context: 'Your concern shows good awareness. When pain medication is used as prescribed for acute pain, the risk of addiction is very low. We will manage your pain with the lowest effective dose and plan to transition to non-opioid options as your healing progresses. Please tell me if your pain is not adequately controlled.'","Evidence-based opioid fear reduction.","beginner"),
  q("sq-bg14-11",ip,"star_examples","Describe preventing a patient safety incident.","Share a safety catch example.","I noticed a patient's antibiotic was labeled for room 412 but I was caring for room 414. The barcode scan would have caught it, but I caught it visually first because I always read labels before scanning. I returned the medication to pharmacy and reported the near-miss. The pharmacist identified a dispensing error that could have affected multiple patients.","Pre-scan visual safety catch.","beginner"),
  q("sq-bg14-12",ws,"prioritization","You have a patient with a new arrhythmia and another needing a scheduled medication.","How would you prioritize a new arrhythmia versus a scheduled medication?","The new arrhythmia takes priority: I would assess the patient immediately, obtain a 12-lead ECG, check vital signs, and notify the provider. If the arrhythmia is stable, I would then administer the scheduled medication within the acceptable window. If unstable, the scheduled medication can wait while I manage the emergency.","Arrhythmia priority with medication timing flexibility.","beginner"),
  q("sq-bg14-13",ws,"delegation","You need to delegate vital signs on a post-transfusion patient.","How would you delegate post-transfusion monitoring?","I would specify: 'Vital signs every 15 minutes during the transfusion and 1 hour after completion. Watch for and immediately report: temperature increase greater than 1 degree, any rash or hives, complaints of back pain, chills, difficulty breathing, or any new symptoms. Do not adjust the infusion rate.'","Post-transfusion vital sign delegation.","beginner"),
  q("sq-bg14-14",ws,"patient_safety","A patient develops hyperglycemic hyperosmolar state.","How would you manage HHS?","HHS presents with severe hyperglycemia (>600 mg/dL), hyperosmolality, dehydration, and altered consciousness without significant ketoacidosis. I would administer aggressive IV fluid resuscitation (isotonic then hypotonic saline), low-dose insulin infusion, monitor electrolytes every 2 hours, replace potassium as levels drop, and identify the precipitating cause. Fluid replacement is more critical than insulin initially.","HHS fluid-first management approach.","advanced"),
  q("sq-bg14-15",ws,"medication_error","A nurse prepares a medication and labels it with the wrong patient name.","How would you prevent medication labeling errors?","I would label medications immediately after preparation with the patient's name, drug name, dose, and time. I would never prepare medications for multiple patients simultaneously, verify labels against the original order before administration, and use the barcode scanner as a final verification step.","Medication labeling best practices.","beginner"),
  q("sq-bg14-16",ws,"handoff_communication","You are handing off a patient who is a potential organ donor.","How would you communicate organ donation status?","I would include: 'Mr. Davis is brain dead as declared by Dr. Smith at 1400. The organ procurement organization has been contacted. Family has consented to organ donation. Hemodynamic management goals per OPO: MAP >65, urine output >1 mL/kg/hr. Current medications: vasopressin, levothyroxine. Donor workup labs pending. OPO coordinator is Sarah, phone [number].'","Organ donor management handoff.","intermediate"),
  q("sq-bg14-17",ws,"difficult_coworkers","A colleague undermines your authority in front of patients.","How would you handle being undermined in front of patients?","I would address it calmly in the moment: 'Let me clarify—I have verified this with the physician and this is the correct plan.' Privately later: 'When you contradicted me in front of the patient, it undermined their trust in their care. If you have concerns about a clinical decision, please discuss them with me privately first.'","Public undermining correction with private discussion.","intermediate"),
  q("sq-bg14-18",ws,"interdisciplinary_communication","An ethics consult is needed for a complex case.","How would you initiate an ethics consultation?","I would document specific ethical concerns, discuss with the attending physician, contact the ethics committee through the facility's process, prepare a summary of the ethical dilemma including all perspectives, and ensure the patient and family are informed about the consultation. Ethics consultations provide guidance but are typically advisory, not binding.","Ethics consultation initiation process.","intermediate"),
  q("sq-bg14-19",ct,"first_shift","You accidentally contaminate a sterile field.","How would you handle sterile field contamination?","I would stop the procedure, acknowledge the contamination, discard the contaminated supplies, and set up a new sterile field. I would not try to save the field or proceed with compromised sterility. I would be transparent: 'I contaminated the field. Let me set up a new one.' Honesty about contamination protects patients from infection.","Sterile field contamination honesty.","beginner"),
  q("sq-bg14-20",ct,"new_nurse_anxiety","You are worried about nursing burnout.","How would you prevent early-career burnout?","I would recognize warning signs early: emotional exhaustion, depersonalization, and decreased sense of accomplishment. I would maintain self-care routines, set work-life boundaries, develop peer support networks, use EAP resources, find meaning in my work through patient connections, and accept that I cannot save everyone. Prevention is more effective than recovery.","Early burnout prevention strategy.","beginner"),
  q("sq-bg14-21",ct,"time_management","You need to coordinate care for a patient being discharged today.","How would you organize a same-day discharge?","I would start early: verify discharge criteria are met, complete medication reconciliation, arrange follow-up appointments, provide discharge education using teach-back, ensure prescriptions are sent to the pharmacy, coordinate DME delivery, complete discharge documentation, arrange transportation, and communicate discharge timing to the bed management team.","Same-day discharge coordination checklist.","beginner"),
  q("sq-bg14-22",ct,"documentation_challenges","You need to document an incident involving a visitor.","How would you document a visitor-related incident?","I would document objectively: 'Visitor identified as patient's son became verbally aggressive toward nursing staff at 1430. Security was called. Visitor was counseled by security and agreed to modify behavior. Patient was assessed and showed no signs of distress. Visiting restrictions discussed with the patient and family. Safety plan updated.'","Visitor incident objective documentation.","beginner"),
  q("sq-bg14-23",ct,"critical_thinking_drills","A patient's aPTT is 90 seconds on heparin.","How would you respond to a significantly elevated aPTT?","aPTT of 90 (therapeutic usually 60-80 for heparin, normal 25-35) indicates excessive anticoagulation. I would hold the heparin infusion, assess for bleeding, notify the physician, recheck aPTT per protocol, and resume at a reduced rate when ordered. For minor elevation, rate adjustment may suffice. For major bleeding, protamine sulfate reverses heparin.","Elevated aPTT with heparin management.","intermediate"),
  q("sq-bg14-24",pd,"professional_boundaries","You develop compassion fatigue from caring for chronically ill children.","How would you manage compassion fatigue?","I would recognize it early: emotional numbness, dreading work, irritability, and decreased empathy. I would implement: regular debriefing, professional counseling, compassion fatigue prevention workshops, self-care practices, peer support, and considering a temporary unit change if needed. Compassion fatigue is an occupational hazard that requires proactive management.","Compassion fatigue early recognition and management.","intermediate"),
  q("sq-bg14-25",pd,"ethical_dilemmas","A pharmaceutical representative offers your unit expensive gifts.","How would you handle pharmaceutical industry gifts?","I would follow facility policy: most institutions prohibit gifts above a nominal value. I would decline: 'Thank you, but our facility policy limits what we can accept from pharmaceutical representatives. We rely on evidence-based prescribing rather than marketing relationships.' Pharmaceutical gifts create implicit bias in prescribing practices.","Pharmaceutical gift policy compliance.","beginner"),
  q("sq-bg14-26",pd,"advocacy","A patient's care is being fragmented across too many specialists.","How would you advocate for coordinated care?","I would identify the care coordination gap, request a multidisciplinary care conference, suggest designating a primary physician for coordinating specialist recommendations, communicate discrepancies between specialist plans, and serve as the patient's advocate for unified care. Fragmented care leads to medication errors, conflicting plans, and patient confusion.","Care coordination advocacy.","intermediate"),
  q("sq-bg14-27",pd,"patient_communication","A patient needs to make a decision about surgery.","How would you support surgical decision-making?","I would help the patient prepare: 'Before your surgeon visits, let us organize your questions. What matters most to you about this decision? What are you most afraid of? What does your ideal outcome look like? Writing these down ensures you communicate clearly with your surgeon and make a decision aligned with your values.'","Surgical decision preparation support.","beginner"),
  q("sq-bg14-28",pd,"workplace_bullying","A nurse sabotages your patient care by withholding information.","How would you address care sabotage?","This is a patient safety issue requiring immediate action. I would document the specific instance, report to the charge nurse and manager, verify all patient information independently, and frame the report around patient safety: 'Critical patient information was withheld during handoff, which placed the patient at risk. I need to report this as a safety concern.'","Care sabotage as patient safety report.","intermediate"),
  q("sq-bg14-29",cn,"job_offer_negotiation","You want to understand benefits packages.","What benefits should you evaluate beyond salary?","I would evaluate: health insurance premiums and coverage, retirement plan matching, PTO and sick time, shift differentials and overtime policy, tuition reimbursement amount, certification bonus, signing bonus, relocation assistance, student loan repayment programs, childcare benefits, and wellness programs. Total compensation often exceeds base salary by 25-40%.","Comprehensive benefits evaluation.","beginner"),
  q("sq-bg14-30",cn,"probation_period","You want to build trust with your manager.","How would you establish trust during probation?","I would demonstrate: consistent attendance and punctuality, following through on commitments, communicating proactively about problems, accepting accountability, showing improvement from feedback, maintaining professional behavior, and being honest about my capabilities and limitations. Trust is built through consistent, reliable behavior over time.","Trust-building behaviors during probation.","beginner"),
  q("sq-bg14-31",cn,"career_advancement","You want to understand nursing scope of practice.","Why is understanding scope of practice critical?","Scope of practice defines what a nurse can legally and professionally do. It varies by license type (RN, LPN, NP), state regulations, facility policies, and individual competency. Practicing outside scope creates legal liability, endangers patients, and risks license revocation. I would know my scope thoroughly and never exceed it, even under pressure.","Scope of practice legal protection importance.","beginner"),
  q("sq-bg14-32",cn,"performance_evaluation","You want to prepare for a difficult evaluation conversation.","How would you prepare for an evaluation with areas of concern?","I would prepare by: honestly assessing my own areas for improvement, gathering specific examples of progress, developing an action plan for each concern area, approaching the conversation with openness rather than defensiveness, asking for specific support needed, and setting measurable goals with timelines. Acknowledging weaknesses proactively demonstrates professional maturity.","Difficult evaluation preparation.","beginner"),
  q("sq-bg14-33",ip,"clinical_judgment","A patient develops acute mitral stenosis symptoms.","How does mitral stenosis present?","Mitral stenosis restricts blood flow from the left atrium to the left ventricle, causing left atrial enlargement, pulmonary congestion, and atrial fibrillation. Symptoms include dyspnea, orthopnea, hemoptysis, and a characteristic opening snap with low-pitched rumbling murmur. I would manage heart rate, administer diuretics, anticoagulate for AFib, and prepare for possible valvuloplasty or replacement.","Mitral stenosis presentation and management.","advanced"),
  q("sq-bg14-34",ws,"patient_safety","A patient develops acute compartment syndrome in their forearm after IV infiltration.","How would you manage forearm compartment syndrome?","I would remove all circumferential dressings, elevate the extremity to heart level (not above), assess neurovascular status, measure compartment pressure if available, notify the surgeon immediately for possible fasciotomy, and manage pain. Compartment pressure exceeding 30 mmHg or within 30 mmHg of diastolic pressure typically requires surgical decompression.","Compartment syndrome post-IV infiltration.","advanced"),
  q("sq-bg14-35",ct,"critical_thinking_drills","A patient's prothrombin time is 20 seconds.","What does an elevated PT indicate?","PT of 20 (normal 11-13.5) measures the extrinsic and common coagulation pathways. Elevated PT suggests: warfarin effect, liver disease, vitamin K deficiency, factor VII deficiency, or DIC. I would check INR for warfarin patients, assess liver function, and evaluate for bleeding risk. PT/INR guides warfarin dosing and monitors liver synthetic function.","PT interpretation with cause differentiation.","beginner"),
  q("sq-bg14-36",pd,"ethical_dilemmas","You discover a medication error that occurred on the previous shift.","How would you handle discovering a previous shift's error?","I would assess the patient immediately for adverse effects, notify the provider, document the discovery and current assessment, file a safety report, and inform the charge nurse. I would not confront the previous shift nurse directly—the safety reporting system investigates errors objectively. My priority is patient safety, not assigning blame.","Previous shift error discovery management.","beginner"),
  q("sq-bg14-37",cn,"career_advancement","You want to understand telehealth nursing.","What does telehealth nursing involve?","Telehealth nursing uses technology to provide remote patient care: triage calls, chronic disease management, post-discharge follow-up, and remote monitoring. Skills needed include: strong assessment abilities without physical examination, excellent telephone communication, technology proficiency, and clinical decision-making with limited data. Telehealth is expanding rapidly and offers scheduling flexibility.","Telehealth nursing career overview.","beginner"),
  q("sq-bg14-38",ip,"clinical_judgment","A patient develops peripartum cardiomyopathy.","How would you recognize peripartum cardiomyopathy?","Peripartum cardiomyopathy develops in the last month of pregnancy or within 5 months postpartum, presenting with heart failure symptoms: dyspnea, orthopnea, fatigue, and edema. It can be easily missed as pregnancy-related discomfort. Diagnosis requires echocardiography showing reduced ejection fraction. Treatment includes standard heart failure management with pregnancy-safe medications.","Peripartum cardiomyopathy recognition.","advanced"),
  q("sq-bg14-39",ws,"medication_error","A patient's medication list has not been updated after a specialist visit.","How would you ensure medication list accuracy after specialist visits?","I would review any new specialist orders or recommendations, compare with the current medication list, identify discrepancies, clarify with the prescribing physician, update the medication list accordingly, and communicate changes to the patient. Post-specialist medication reconciliation prevents duplicate therapy and missed medications.","Post-specialist medication reconciliation.","beginner"),
  q("sq-bg14-40",ct,"documentation_challenges","You need to document that a patient understands their rights.","How would you document patient rights acknowledgment?","I would document: 'Patient rights and responsibilities reviewed with patient using facility-provided materials. Patient verbalized understanding of: right to informed consent, right to refuse treatment, right to privacy, right to a safe environment, complaint process, and advance directive information. Written acknowledgment signed and placed in chart. Patient had no questions.'","Patient rights documentation.","beginner"),
  q("sq-bg14-41",ip,"clinical_judgment","A patient develops sick sinus syndrome.","How would you manage sick sinus syndrome?","Sick sinus syndrome presents with alternating tachycardia and bradycardia (tachy-brady syndrome), sinus arrest, and sinus node exit block. Medications for tachycardia can worsen bradycardia and vice versa. Definitive treatment is permanent pacemaker implantation, which then allows safe use of rate-controlling medications for the tachycardia episodes.","Sick sinus syndrome pacemaker-first approach.","advanced"),
  q("sq-bg14-42",ws,"patient_safety","A patient on a PCA pump is oversedated.","How would you manage PCA oversedation?","I would stop the PCA, assess airway and breathing, stimulate the patient, administer naloxone (Narcan) if respiratory depression is present, continue monitoring, adjust PCA settings with the physician, and investigate the cause. PCA lockout intervals should prevent oversedation—oversedation may indicate incorrect pump programming or additional sedating medications.","PCA oversedation with naloxone and cause analysis.","intermediate"),
  q("sq-bg14-43",ct,"critical_thinking_drills","A patient's albumin-to-creatinine ratio shows microalbuminuria.","What does microalbuminuria indicate?","Microalbuminuria (30-300 mg/g creatinine) is the earliest sign of diabetic nephropathy and indicates kidney damage before creatinine rises. I would ensure the patient is on an ACE inhibitor or ARB for renal protection, optimize blood glucose and blood pressure control, and recheck annually. Early intervention can slow or prevent progression to overt nephropathy.","Microalbuminuria as early nephropathy marker.","intermediate"),
  q("sq-bg14-44",pd,"patient_communication","A patient is embarrassed about needing help with personal hygiene.","How would you help a patient who is embarrassed about hygiene needs?","I would normalize the situation: 'Many patients need help with personal care while they are in the hospital. This is a temporary situation and nothing to be embarrassed about. Maintaining good hygiene is important for your recovery, and helping you with this is a normal part of my care. Your dignity and comfort are my priority.'","Hygiene embarrassment normalization.","beginner"),
  q("sq-bg14-45",cn,"career_advancement","You want to develop expertise in wound care.","How would you specialize in wound care nursing?","I would gain experience with diverse wound types, pursue WOC (Wound, Ostomy, and Continence) nursing certification, complete a WOCN education program, develop skills in wound assessment, staging, and advanced dressing techniques, learn about negative pressure wound therapy, and understand nutrition's role in wound healing. WOC nurses are in high demand across all settings.","Wound care nursing specialization.","intermediate"),
  q("sq-bg14-46",ip,"clinical_judgment","A patient develops Wellens syndrome on ECG.","What does Wellens syndrome indicate?","Wellens syndrome shows deeply inverted T waves or biphasic T waves in V2-V3 during pain-free intervals, indicating critical proximal LAD stenosis. The patient may appear asymptomatic between episodes. This pattern predicts anterior wall MI without intervention. I would ensure cardiology consultation for urgent catheterization. Stress testing is contraindicated due to high MI risk.","Wellens syndrome LAD warning pattern.","advanced"),
  q("sq-bg14-47",ws,"delegation","You need to delegate ambulation for a patient with orthostatic hypotension.","How would you delegate ambulation with orthostatic precautions?","I would specify: 'Check her blood pressure lying, sitting, and standing before walking. If systolic drops more than 20 points or she feels dizzy, return her to bed. Have her sit at the bedside for 2 minutes before standing. Walk slowly with a gait belt. Stay close and watch for unsteadiness. Do not leave her unsupervised during ambulation.'","Orthostatic precaution ambulation delegation.","beginner"),
  q("sq-bg14-48",ct,"new_nurse_anxiety","You are overwhelmed by the responsibility of human lives.","How would you manage the weight of responsibility?","I would remind myself that I am part of a team—patient safety does not rest on my shoulders alone. I would follow protocols, verify my decisions, ask for help, and maintain perspective: billions of nursing interactions worldwide are safe every day. The anxiety shows I take my role seriously, and that seriousness makes me a safer nurse.","Responsibility weight perspective and team reliance.","beginner"),
  q("sq-bg14-49",pd,"advocacy","A patient's insurance is denying a prescribed treatment.","How would you support an insurance appeal?","I would ensure thorough clinical documentation supporting medical necessity, help the physician craft a strong appeal letter, involve case management, educate the patient about their appeal rights, explore patient assistance programs, and escalate through the hospital's insurance advocacy resources. Patients should not be denied medically necessary treatment due to administrative barriers.","Insurance appeal support process.","intermediate"),
  q("sq-bg14-50",cn,"career_advancement","You want to understand the role of nursing in disaster preparedness.","How would nurses contribute to disaster preparedness?","Nurses play critical roles: triage and emergency care, public health surveillance, vaccination and prophylaxis campaigns, mental health support, community education, disaster planning committees, and Medical Reserve Corps volunteering. Disaster nursing requires: flexibility, autonomous practice skills, physical stamina, and emotional resilience. FEMA and Red Cross offer nurse volunteer programs.","Disaster nursing role overview.","beginner"),
  q("sq-bg14-51",ip,"clinical_judgment","A patient develops commotio cordis after chest impact.","What is commotio cordis?","Commotio cordis is sudden cardiac arrest from a blunt chest impact timed to the vulnerable period of the cardiac cycle (20ms before the T-wave peak), causing ventricular fibrillation in a structurally normal heart. Most common in young athletes. Immediate defibrillation is the only treatment. AED access in sports settings saves lives.","Commotio cordis with immediate defibrillation.","advanced"),
  q("sq-bg14-52",ws,"patient_safety","A patient's central line dressing is loose and needs changing.","How would you perform a central line dressing change?","I would gather supplies, perform hand hygiene, don sterile gloves, carefully remove the old dressing, assess the insertion site for signs of infection (redness, drainage, tenderness), clean with chlorhexidine using back-and-forth friction for 30 seconds, allow to dry completely, apply the transparent dressing and secure, date and initial the dressing, and document my assessment findings.","Central line dressing change technique.","beginner"),
  q("sq-bg14-53",ct,"critical_thinking_drills","A patient's hemoglobin and hematocrit are both dropping without visible bleeding.","What does a declining H&H without visible bleeding suggest?","Declining H&H without visible bleeding suggests: internal hemorrhage (GI, retroperitoneal, intra-abdominal), hemolysis, or hemodilution from excessive IV fluids. I would check for signs of occult bleeding (guaiac stool, abdominal distension), assess for hemolysis markers (LDH, bilirubin, haptoglobin), review IV fluid volumes, and monitor hemodynamic stability.","Occult bleeding versus hemolysis versus hemodilution.","intermediate"),
  q("sq-bg14-54",pd,"ethical_dilemmas","A patient wants to leave AMA but does not understand the risks.","How would you ensure informed AMA departure?","I would assess their capacity, clearly explain the specific risks of leaving (not generic risks), document their understanding or lack thereof, ensure the physician has spoken with them, attempt to address the underlying reason for wanting to leave, provide discharge instructions and prescriptions even for AMA patients, and arrange follow-up care.","Informed AMA with continued care provision.","intermediate"),
  q("sq-bg14-55",cn,"career_advancement","You want to understand nursing unions.","What should nurses know about nursing unions?","Nursing unions negotiate: nurse-to-patient ratios, wages, benefits, workplace safety, disciplinary processes, and professional practice standards. Unionized nurses typically earn higher wages and have stronger workplace protections. Non-union environments may offer more individual negotiation flexibility. Understanding labor rights helps nurses advocate for safe working conditions regardless of union status.","Nursing union overview.","beginner"),
  q("sq-bg14-56",ip,"clinical_judgment","A patient develops Dressler's syndrome after MI.","What is Dressler's syndrome?","Dressler's syndrome is post-myocardial infarction pericarditis occurring 2-10 weeks after MI, presenting with pleuritic chest pain, friction rub, fever, and pericardial effusion. It is an autoimmune-mediated inflammatory response to myocardial necrosis. Treatment includes NSAIDs and colchicine. I would differentiate from recurrent MI and monitor for tamponade.","Dressler's syndrome post-MI pericarditis.","advanced"),
  q("sq-bg14-57",ws,"interdisciplinary_communication","A nurse educator identifies a knowledge gap on your unit.","How would you participate in addressing a unit knowledge gap?","I would volunteer to help develop education, share relevant research, participate in in-service training, model correct practice, and support colleagues in implementing new knowledge. I would frame it positively: 'This is an opportunity for our whole team to improve. How can I help with the education plan?' Professional growth is a team effort.","Knowledge gap collaborative response.","beginner"),
  q("sq-bg14-58",ct,"documentation_challenges","You need to create an addendum to a previous note.","How would you properly create a documentation addendum?","I would add a new entry clearly labeled: 'Addendum to [date/time] note.' I would state the reason for the addendum and provide the additional or corrected information. I would never alter the original entry. Addendums must be timely, factual, and clearly connected to the original documentation. Electronic systems have specific addendum functions.","Proper addendum creation.","beginner"),
  q("sq-bg14-59",pd,"patient_communication","A family member is angry about perceived poor care.","How would you de-escalate an angry family member?","I would listen actively without interrupting, validate their concern, avoid defensive language, focus on what I can do: 'I hear that you are frustrated with the wait time for pain medication. That is not acceptable and I am going to address it right now. Let me check on the medication and I will be back within 10 minutes with an update.'","Family anger de-escalation with action commitment.","beginner"),
  q("sq-bg14-60",cn,"career_advancement","You want to understand healthcare law basics.","What legal concepts should every nurse understand?","Essential legal concepts: scope of practice and its boundaries, standard of care and how it is determined, informed consent requirements, advance directive laws, mandatory reporting obligations, HIPAA regulations, documentation as legal evidence, professional liability and malpractice elements, and Good Samaritan laws. Legal knowledge protects both nurses and patients.","Healthcare law essentials for nurses.","beginner"),
  q("sq-bg14-61",ip,"clinical_judgment","A patient develops idiopathic intracranial hypertension.","How would you manage pseudotumor cerebri?","IIH presents with headache, visual changes, papilledema, and elevated opening pressure on LP in an obese young woman. Treatment includes acetazolamide, weight loss, serial LP if needed, and ophthalmology monitoring. Untreated IIH causes progressive vision loss. I would monitor visual acuity and fields regularly and ensure the patient understands the importance of weight management.","IIH management with vision preservation.","intermediate"),
  q("sq-bg14-62",ws,"patient_safety","A patient with dementia is at risk for wandering off the unit.","How would you prevent elopement of a confused patient?","I would implement: bed alarm, door alarms, wander guard bracelet, close nurse station proximity, frequent rounding, meaningful activities to reduce restlessness, family presence when possible, and environmental modifications. I would avoid physical restraints as first intervention and use least restrictive measures that maintain safety while preserving dignity.","Elopement prevention with least restrictive measures.","beginner"),
  q("sq-bg14-63",ct,"time_management","You are constantly interrupted during medication administration.","How would you reduce medication pass interruptions?","I would wear a 'Do Not Disturb' indicator during medication passes, educate colleagues about interruption-related medication errors, pre-round to address patient needs before starting medications, delegate non-urgent tasks, and advocate for unit policies that protect medication administration time. Studies show each interruption increases medication error risk by 12.7%.","Interruption reduction for medication safety.","beginner"),
  q("sq-bg14-64",pd,"workplace_bullying","You witness a nurse physically intimidating a colleague.","How would you respond to physical intimidation in the workplace?","I would intervene immediately to ensure safety, report the incident to the charge nurse and manager, document what I witnessed objectively, support the colleague who was intimidated, and follow up through HR if needed. Physical intimidation in the workplace is unacceptable and potentially criminal. No one should feel physically unsafe at work.","Physical intimidation immediate intervention.","intermediate"),
  q("sq-bg14-65",cn,"probation_period","You want to contribute to unit culture as a new member.","How would you positively influence unit culture during orientation?","I would model positivity by: supporting colleagues without being asked, expressing genuine appreciation for help, avoiding gossip, bringing solutions rather than just problems, participating in unit social events, and demonstrating consistent professionalism. New nurses can positively influence culture by embodying the values they want to see in their workplace.","Positive culture contribution strategies.","beginner"),
  q("sq-bg14-66",ip,"clinical_judgment","A patient develops Wolff-Parkinson-White syndrome on ECG.","What is WPW and why is it dangerous?","WPW shows a short PR interval with a delta wave indicating an accessory pathway that can conduct rapid atrial rhythms directly to the ventricles, bypassing the AV node's protective slowing. If atrial fibrillation occurs, it can degenerate to ventricular fibrillation. AV nodal blockers (adenosine, beta-blockers, calcium channel blockers, digoxin) are contraindicated—they force conduction through the accessory pathway.","WPW with AV nodal blocker contraindication.","advanced"),
  q("sq-bg14-67",ws,"handoff_communication","You are giving report on a dying patient.","How would you hand off an actively dying patient?","I would communicate: 'Mrs. Chen is actively dying. Comfort measures only. Morphine 2mg IV every 2 hours PRN for respiratory distress and pain. She is Cheyne-Stokes breathing. Her family has been present and is aware. The chaplain visited at 1500. Allow unlimited visitors. Keep the room quiet and comfortable. The funeral home paperwork is in the chart.'","Actively dying patient compassionate handoff.","intermediate"),
  q("sq-bg14-68",ct,"critical_thinking_drills","A patient's serum osmolality is 320 mOsm/kg.","What does elevated serum osmolality indicate?","Serum osmolality of 320 (normal 275-295) indicates concentrated serum from dehydration, hyperglycemia, or uremia. I would calculate the osmolal gap (measured minus calculated) to check for toxic alcohol ingestion. In DKA, osmolality rises from glucose and ketones. I would address the underlying cause with appropriate hydration and treatment.","Serum osmolality with osmolal gap calculation.","intermediate"),
  q("sq-bg14-69",pd,"advocacy","A patient needs wound care supplies but cannot afford them.","How would you help a patient access wound care supplies?","I would involve social work, research patient assistance programs from wound supply manufacturers, contact local wound care charitable organizations, check if the patient qualifies for Medicaid, explore home health services that provide supplies, and ensure the patient has enough supplies to last until the next appointment before discharge.","Wound supply affordability advocacy.","beginner"),
  q("sq-bg14-70",cn,"career_advancement","You want to understand the benefits of BSN completion.","Why should ADN nurses pursue BSN completion?","BSN completion is associated with: reduced patient mortality rates, better critical thinking skills, enhanced career opportunities, leadership preparation, and eligibility for graduate programs. Many hospitals prefer or require BSN, and Magnet designation requires 80% BSN-prepared staff. RN-to-BSN programs are widely available online and can be completed while working.","BSN completion clinical and career benefits.","beginner"),
  q("sq-bg14-71",ip,"clinical_judgment","A patient develops acute interstitial nephritis from medication.","How would you recognize drug-induced AIN?","Drug-induced AIN presents with AKI, fever, rash, and eosinophilia (classic triad, though not always complete). Common culprits include NSAIDs, antibiotics (penicillins, cephalosporins), and PPIs. Treatment involves stopping the offending medication and possibly corticosteroids. Urine eosinophils may be present. I would review all medications and identify the most likely causative agent.","Drug-induced AIN recognition with medication review.","intermediate"),
  q("sq-bg14-72",ws,"patient_safety","A patient with a chest tube accidentally disconnects the drainage system.","How would you manage chest tube drainage system disconnection?","I would clamp the chest tube temporarily only if it is disconnected from the drainage system and there is an air leak. I would submerge the end in sterile water or saline as a temporary water seal, reconnect the drainage system or set up a new one, assess the patient for respiratory distress and pneumothorax, and notify the physician.","Chest tube disconnection emergency management.","intermediate"),
  q("sq-bg14-73",ct,"new_nurse_anxiety","You feel guilty about taking days off.","How would you manage guilt about taking time off?","I would recognize that rest is not laziness—it is essential for safe patient care. Fatigued nurses make more errors, have poorer clinical judgment, and burn out faster. Taking scheduled time off is a professional obligation to my patients and myself. I would plan my time off in advance, prepare my colleagues, and disconnect fully.","Time-off guilt professional reframing.","beginner"),
  q("sq-bg14-74",pd,"patient_communication","A patient wants to record their education session.","How would you handle a patient wanting to record education?","I would support it: 'That is actually a great idea. Recording our education session means you can review the information at home. Let me make sure I cover everything clearly. You can also share it with family members who are helping with your care.' I would ensure no other patient information is captured in the recording.","Education recording as learning support.","beginner"),
  q("sq-bg14-75",cn,"career_advancement","You want to prepare for a leadership role.","What specific steps prepare you for nursing leadership?","I would: take on progressive responsibilities (charge nurse, committee chair), complete leadership education, seek mentorship from established leaders, develop financial literacy and budget understanding, learn about regulatory compliance, practice difficult conversations, build a professional network, and demonstrate consistent excellence in clinical practice. Leadership readiness is built through intentional development.","Nursing leadership preparation roadmap.","beginner"),
  q("sq-bg14-76",ip,"clinical_judgment","A patient on bivalirudin develops hemorrhage.","How would you manage bivalirudin-related bleeding?","Bivalirudin is a direct thrombin inhibitor with a short half-life (25 minutes). Unlike heparin, it has no specific reversal agent. For bleeding, I would stop the infusion (the drug clears quickly due to short half-life), provide supportive hemostatic measures, transfuse as needed, and avoid hemodialysis (bivalirudin is removed by hemodialysis). The short half-life is actually advantageous.","Bivalirudin bleeding management with short half-life advantage.","advanced"),
  q("sq-bg14-77",ws,"medication_error","A patient is prescribed two medications from the same class.","How would you address therapeutic class duplication?","I would question the duplication with pharmacy and the prescriber: 'I noticed the patient is prescribed both lisinopril and ramipril, which are both ACE inhibitors. Was this intentional, or should one be discontinued?' I would not administer both without clarification. Therapeutic duplication increases adverse effect risk without proportional therapeutic benefit.","Therapeutic class duplication verification.","beginner"),
  q("sq-bg14-78",ct,"documentation_challenges","You need to document a telephone order accurately.","How would you document a telephone order?","I would document: 'Telephone order received from Dr. [name] at [time]: [complete order]. Read back verified. Nurse signature: [name, credentials].' I would include the clinical reason for the order, ensure the physician co-signs within the facility-required timeframe, and flag any order that seems inconsistent with the patient's condition.","Telephone order documentation with read-back.","beginner"),
  q("sq-bg14-79",pd,"ethical_dilemmas","A nurse colleague confides that they are impaired at work.","How would you handle a colleague's impairment disclosure?","I would prioritize patient safety: 'I care about you and your career, but I cannot ignore impairment that affects patient safety. I will help you access the peer assistance program, but if you are impaired right now, you cannot continue patient care.' I would report to the charge nurse immediately if the colleague refuses to remove themselves from patient care.","Impaired colleague safety-first response.","intermediate"),
  q("sq-bg14-80",cn,"career_advancement","You want to understand the value of professional organization membership.","Why should nurses join professional organizations?","Professional organizations provide: continuing education, networking opportunities, advocacy representation, certification resources, career development, access to research, mentorship programs, conference discounts, professional liability insurance, and collective voice in policy discussions. Membership demonstrates professional commitment and connects you to a broader nursing community.","Professional organization membership benefits.","beginner"),
  q("sq-bg14-81",ip,"clinical_judgment","A patient develops Takotsubo cardiomyopathy.","What is Takotsubo (stress) cardiomyopathy?","Takotsubo cardiomyopathy is acute, reversible left ventricular dysfunction triggered by severe emotional or physical stress, mimicking acute MI with chest pain, ST changes, and troponin elevation. Angiography shows no coronary obstruction, and echocardiography reveals characteristic apical ballooning. Treatment is supportive with heart failure medications. Most patients recover completely within weeks.","Takotsubo cardiomyopathy recognition and reversibility.","advanced"),
  q("sq-bg14-82",ws,"patient_safety","A patient on a continuous infusion's IV pump runs out of battery.","How would you manage IV pump battery failure?","I would immediately connect to AC power, verify the infusion is still running, check that settings are maintained, assess the patient for missed medication effects, restart the infusion if it stopped, and report the equipment failure to biomedical engineering. I would ensure backup batteries are available for critical infusions. Never rely solely on battery power for essential medications.","IV pump battery failure management.","beginner"),
  q("sq-bg14-83",ct,"critical_thinking_drills","A patient's magnesium is 3.5 mEq/L.","What does hypermagnesemia cause?","Magnesium of 3.5 (normal 1.5-2.5) can cause hypotension, bradycardia, diminished reflexes, and respiratory depression. Severe hypermagnesemia (>5) can cause cardiac arrest. Most common cause is iatrogenic—excessive supplementation, especially in renal failure. I would hold magnesium supplements, check deep tendon reflexes, administer IV calcium gluconate as an antagonist, and monitor cardiac rhythm.","Hypermagnesemia recognition with calcium antagonism.","intermediate"),
  q("sq-bg14-84",pd,"advocacy","A patient needs a specialized bed but the unit does not have one available.","How would you obtain specialized equipment urgently?","I would contact the bed management coordinator, check other units for available specialty beds, contact the equipment vendor for emergency rental, escalate through nursing management if there is delay, document the clinical need and any equipment-related complications, and ensure the patient receives appropriate interim positioning and pressure relief.","Urgent specialty bed procurement advocacy.","beginner"),
  q("sq-bg14-85",cn,"career_advancement","You want to understand the impact of nursing on healthcare quality.","How do nurses impact healthcare quality metrics?","Nurses directly influence: mortality rates, readmission rates, hospital-acquired infection rates, falls, pressure injuries, patient satisfaction (HCAHPS), medication error rates, and length of stay. Higher nurse staffing levels, BSN education, and specialty certification are all associated with better patient outcomes. Nurses are the largest healthcare workforce and the primary determinant of care quality.","Nursing impact on quality metrics evidence.","beginner"),
  q("sq-bg14-86",ip,"clinical_judgment","A patient develops left bundle branch block.","What is the clinical significance of new LBBB?","New LBBB can indicate acute MI (treated as STEMI-equivalent per guidelines), cardiomyopathy, or conduction system disease. LBBB makes standard ST-segment analysis unreliable for MI diagnosis. Sgarbossa criteria help identify MI in the presence of LBBB. I would treat new LBBB with chest pain as a STEMI-equivalent and activate the cath lab.","New LBBB as STEMI-equivalent with Sgarbossa criteria.","advanced"),
  q("sq-bg14-87",ws,"handoff_communication","A patient's family has specific communication preferences.","How would you communicate family preferences during handoff?","I would include: 'The Rodriguez family prefers: updates given to the wife only (per patient request), physician calls after 2 PM, all discussions in person rather than by phone, interpreter services for clinical discussions, and their parish priest to be contacted if condition worsens. These preferences are documented in the care plan.'","Family communication preference handoff.","beginner"),
  q("sq-bg14-88",ct,"time_management","You need to complete annual competency requirements.","How would you manage competency completion alongside clinical work?","I would create a timeline at the beginning of the year, complete modules during downtime or educational leave, prioritize clinical competencies that require scheduling (BLS renewal, skills validation), and avoid last-minute rushing that leads to superficial learning. I would view competency requirements as genuine learning opportunities rather than bureaucratic burdens.","Annual competency time management.","beginner"),
  q("sq-bg14-89",pd,"professional_boundaries","A patient gifts you a significant amount of money.","How would you handle a large monetary gift?","I would decline respectfully: 'I am deeply touched by your generosity, but I cannot accept monetary gifts. It is against our policy and professional ethics. If you would like to honor your care experience, you could write to our administration about the team, donate to the hospital foundation, or contribute to a nursing scholarship fund.'","Monetary gift professional redirection.","beginner"),
  q("sq-bg14-90",cn,"performance_evaluation","You want to demonstrate evidence-based practice contributions.","How would you showcase EBP contributions during evaluation?","I would present: 'I identified that our unit's fall prevention protocol was not incorporating the latest evidence on mobility-focused interventions. I researched current guidelines, presented findings at our unit meeting, and collaborated with PT to implement a progressive mobility assessment. Our fall rate decreased by 15% over the following quarter.'","EBP contribution with measurable outcome.","intermediate"),
  q("sq-bg14-91",ip,"clinical_judgment","A patient develops torsades de pointes.","How would you manage torsades de pointes?","Torsades de pointes is a polymorphic VT associated with prolonged QT interval. Treatment is IV magnesium sulfate 2g over 10 minutes (even with normal magnesium levels), overdrive pacing to increase heart rate and shorten QT, and removing QT-prolonging agents. Isoproterenol may be used temporarily. Standard antiarrhythmics like amiodarone can worsen torsades by further prolonging QT.","Torsades management with magnesium and amiodarone avoidance.","advanced"),
  q("sq-bg14-92",ws,"patient_safety","A patient in a wheelchair has no seatbelt and is at risk of sliding.","How would you ensure wheelchair safety?","I would apply the wheelchair seatbelt, ensure the footrests are properly positioned, lock the wheels when stationary, adjust the wheelchair to fit the patient, and educate the patient about safe wheelchair use. I would assess whether the patient can safely manage the wheelchair independently or needs assistance. Wheelchair falls cause significant injury.","Wheelchair safety assessment and adjustment.","beginner"),
  q("sq-bg14-93",ct,"documentation_challenges","You need to document a patient's history of present illness.","How would you document HPI in nursing assessment?","I would use OLDCARTS: Onset (when did symptoms start?), Location, Duration, Characteristics (quality, severity), Aggravating factors, Relieving factors, Timing pattern, and associated Symptoms. A thorough HPI provides the foundation for clinical decision-making and should paint a clear picture of the patient's current condition for any reader.","OLDCARTS HPI documentation framework.","beginner"),
  q("sq-bg14-94",pd,"patient_communication","A patient is grieving a new amputation.","How would you support a patient grieving limb loss?","I would be present: 'I can not imagine what you are going through, but I am here to listen whenever you need to talk. Grieving the loss of your leg is natural and there is no right way to feel right now. When you are ready, I can connect you with others who have gone through similar experiences, and our rehabilitation team will help you regain as much independence as possible.'","Amputation grief support with rehabilitation hope.","intermediate"),
  q("sq-bg14-95",cn,"career_advancement","You want to understand the future of nursing.","What trends will shape nursing's future?","Key trends: AI-assisted clinical decision support, genomics and personalized medicine, expanded NP practice authority, population health management, interprofessional team-based care, virtual reality in nursing education, burnout prevention as organizational priority, and nursing-led innovation. Nurses who embrace change and continuous learning will thrive in this evolving landscape.","Nursing future trends overview.","beginner"),
  q("sq-bg14-96",ip,"clinical_judgment","A patient develops Goodpasture's syndrome.","What is Goodpasture's syndrome?","Goodpasture's syndrome is an autoimmune disease with antibodies against glomerular and alveolar basement membranes, causing rapidly progressive glomerulonephritis and pulmonary hemorrhage. It presents with hemoptysis, dyspnea, hematuria, and rapidly declining renal function. Treatment includes plasmapheresis to remove antibodies, immunosuppression, and supportive care. Without treatment, mortality is very high.","Goodpasture's syndrome dual organ involvement.","advanced"),
  q("sq-bg14-97",ws,"patient_safety","A patient at risk for pressure injury has limited mobility.","How would you implement a comprehensive pressure injury prevention plan?","I would implement: Braden scale assessment on admission and regularly, repositioning every 2 hours with documentation, specialty mattress if Braden score indicates, moisture management, nutritional optimization (protein, vitamins), heel elevation, skin assessment with each reposition, and staff education on pressure injury prevention. Every pressure injury stage 3 or higher should be reported.","Comprehensive pressure injury prevention plan.","beginner"),
  q("sq-bg14-98",ct,"critical_thinking_drills","A patient's venous blood gas shows pH 7.25.","How would you interpret a VBG pH of 7.25?","VBG pH of 7.25 indicates acidosis (normal VBG pH 7.31-7.41, slightly lower than arterial). I would determine the cause: check CO2 for respiratory component and bicarbonate for metabolic component. VBG can substitute for ABG in many situations, with venous CO2 approximately 6 higher and pH approximately 0.03-0.04 lower than arterial values.","VBG interpretation with arterial correlation.","intermediate"),
  q("sq-bg14-99",pd,"ethical_dilemmas","You are asked to participate in a procedure you have moral objections to.","How would you handle conscientious objection?","I would communicate my objection to my supervisor early: 'I have a moral objection to this procedure. I am not refusing to care for the patient—I am requesting that another nurse perform this specific procedure.' I would ensure the patient's care is not delayed by arranging alternative coverage. Conscientious objection requires advance communication, not refusal at the bedside.","Conscientious objection with patient care continuity.","intermediate"),
  q("sq-bg14-100",cn,"career_advancement","You want to leave a lasting legacy in nursing.","How would you build a meaningful nursing legacy?","I would focus on: mentoring the next generation of nurses, contributing to evidence-based practice improvements, advocating for systemic changes that benefit patients, developing expertise that others can learn from, maintaining the highest standards of care throughout my career, and treating every patient encounter as an opportunity to make a difference. Legacy is built one interaction at a time.","Nursing legacy through daily excellence.","beginner"),
];
